  NEW.modeOfIssuanceId = NEW.jsonb->>'modeOfIssuanceId';
  NEW.dates_dateTypeId = NEW.jsonb->'dates'->>'dateTypeId';
  NEW.instanceTypeId = NEW.jsonb->>'instanceTypeId';
  RETURN NEW;
END;
$$ language 'plpgsql';

