CREATE TRIGGER instance_bi_bu_update_references_trg
  BEFORE INSERT OR UPDATE ON instance
  FOR EACH ROW EXECUTE PROCEDURE update_instance_references();

CREATE OR REPLACE FUNCTION instance_set_ol_version()
RETURNS trigger AS $$
BEGIN
  CASE TG_OP
    WHEN 'INSERT' THEN
        NEW.jsonb = jsonb_set(NEW.jsonb, '{_version}', to_jsonb(1));
    WHEN 'UPDATE' THEN
      IF NEW.jsonb->'_version' = '-1' THEN
        IF OLD.jsonb->'_version' IS NULL THEN
          NEW.jsonb = NEW.jsonb - '_version';
        ELSE
          NEW.jsonb = jsonb_set(NEW.jsonb, '{_version}', OLD.jsonb->'_version');
        END IF;
      END IF;
      IF NEW.jsonb->'_version' IS DISTINCT FROM OLD.jsonb->'_version' THEN
        RAISE 'Cannot update record % because it has been changed (optimistic locking): '
              'Stored _version is %, _version of request is %',
              OLD.id, OLD.jsonb->'_version', NEW.jsonb->'_version'
              USING ERRCODE = '23F09', TABLE = 'instance', SCHEMA = '${database.defaultSchemaName}';
      END IF;
      NEW.jsonb = jsonb_set(NEW.jsonb, '{_version}',
          to_jsonb(COALESCE(((OLD.jsonb->>'_version')::numeric + 1) % 2147483648, 1)));
  END CASE;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS set_instance_ol_version_trigger
  ON instance CASCADE;

CREATE TRIGGER instance_ol_bi_set_version_trg BEFORE INSERT OR UPDATE OF jsonb
  ON instance
  FOR EACH ROW EXECUTE PROCEDURE instance_set_ol_version();

CREATE OR REPLACE FUNCTION audit_instance_changes()
RETURNS TRIGGER AS $instance_audit$
DECLARE
  jsonb JSONB;
  uuidtext TEXT;
  uuid UUID;
BEGIN
  jsonb = CASE WHEN TG_OP = 'DELETE' THEN OLD.jsonb ELSE NEW.jsonb END;
  uuidtext = md5(jsonb::text);
  uuidtext = overlay(uuidtext placing '4' from 13);
  uuidtext = overlay(uuidtext placing '8' from 17);
  uuid = uuidtext::uuid;
  WHILE EXISTS (SELECT 1 FROM audit_instance WHERE id = uuid) LOOP
    uuid = next_uuid(uuid);
  END LOOP;
  jsonb = jsonb_build_object(
    'id', to_jsonb(uuid::text),
    'record', jsonb,
    'operation', to_jsonb(left(TG_OP, 1)),
    'createdDate', to_jsonb(current_timestamp::text));
  INSERT INTO audit_instance VALUES (uuid, jsonb);
  RETURN CASE WHEN TG_OP = 'DELETE' THEN OLD ELSE NEW END;
END;
$instance_audit$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS audit_instance ON instance CASCADE;
CREATE TRIGGER audit_instance AFTER DELETE ON instance
  FOR EACH ROW EXECUTE PROCEDURE audit_instance_changes();

CREATE OR REPLACE FUNCTION set_instance_status_updated_date()
RETURNS trigger
AS $function$
  BEGIN
    IF (OLD.jsonb->'statusId' IS DISTINCT FROM NEW.jsonb->'statusId') THEN
      -- Date time in "yyyy-MM-dd'T'HH:mm:ss.SSS'Z'" format at UTC (00:00) time zone
      NEW.jsonb = jsonb_set(
        NEW.jsonb, '{statusUpdatedDate}',
        to_jsonb(to_char(CURRENT_TIMESTAMP(3) AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS.ms"Z"'))
      );
    END IF;
    RETURN NEW;
  END;
$function$  LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS set_instance_status_updated_date ON instance;

CREATE TRIGGER set_instance_status_updated_date BEFORE
UPDATE ON instance
FOR EACH ROW EXECUTE PROCEDURE set_instance_status_updated_date();

