CREATE OR REPLACE FUNCTION set_instance_sourceRecordFormat()
  RETURNS TRIGGER AS $$
  BEGIN
    CASE TG_OP
    WHEN 'INSERT' THEN
      NEW.jsonb := NEW.jsonb - 'sourceRecordFormat';
    ELSE
      NEW.jsonb := CASE (SELECT count(*) FROM instance_source_marc WHERE id=NEW.id)
                   WHEN 0 THEN NEW.jsonb - 'sourceRecordFormat'
                   ELSE jsonb_set(NEW.jsonb, '{sourceRecordFormat}', '"MARC-JSON"')
                   END;
    END CASE;
    RETURN NEW;
  END;
  $$ language 'plpgsql';
DROP TRIGGER IF EXISTS set_instance_sourceRecordFormat ON instance CASCADE;
CREATE TRIGGER set_instance_sourceRecordFormat
  BEFORE INSERT OR UPDATE ON instance
  FOR EACH ROW EXECUTE PROCEDURE set_instance_sourceRecordFormat();

CREATE OR REPLACE FUNCTION update_instance_source_marc()
  RETURNS TRIGGER AS $$
  BEGIN
    IF (TG_OP = 'DELETE') THEN
      UPDATE instance
        SET jsonb = jsonb - 'sourceRecordFormat'
        WHERE id = OLD.id;
    ELSE
      UPDATE instance
        SET jsonb = jsonb_set(jsonb, '{sourceRecordFormat}', '"MARC-JSON"')
        WHERE id = NEW.id;
    END IF;
    RETURN NULL;
  END;
  $$ language 'plpgsql';
DROP TRIGGER IF EXISTS update_instance_source_marc ON instance_source_marc CASCADE;
CREATE TRIGGER update_instance_source_marc
  AFTER DELETE OR INSERT OR UPDATE ON instance_source_marc
  FOR EACH ROW EXECUTE PROCEDURE update_instance_source_marc();

