CREATE OR REPLACE FUNCTION holdings_record_set_ol_version()
RETURNS trigger AS $$
BEGIN
  CASE TG_OP
    WHEN 'INSERT' THEN
        NEW.jsonb = jsonb_set(NEW.jsonb, '{_version}', to_jsonb(1));
    WHEN 'UPDATE' THEN
      IF NEW.jsonb->'_version' = '-1' THEN
        IF OLD.jsonb->'_version' IS NULL THEN
          NEW.jsonb = NEW.jsonb - '_version';
        ELSE
          NEW.jsonb = jsonb_set(NEW.jsonb, '{_version}', OLD.jsonb->'_version');
        END IF;
      END IF;
      IF NEW.jsonb->'_version' IS DISTINCT FROM OLD.jsonb->'_version' THEN
        RAISE 'Cannot update record % because it has been changed (optimistic locking): '
              'Stored _version is %, _version of request is %',
              OLD.id, OLD.jsonb->'_version', NEW.jsonb->'_version'
              USING ERRCODE = '23F09', TABLE = 'holdings_record', SCHEMA = '${database.defaultSchemaName}';
      END IF;
      NEW.jsonb = jsonb_set(NEW.jsonb, '{_version}',
          to_jsonb(COALESCE(((OLD.jsonb->>'_version')::numeric + 1) % 2147483648, 1)));
  END CASE;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS set_holdings_record_ol_version_trigger
  ON holdings_record CASCADE;

CREATE TRIGGER holdings_record_ol_bi_set_version_trg BEFORE INSERT OR UPDATE OF jsonb
  ON holdings_record
  FOR EACH ROW EXECUTE PROCEDURE holdings_record_set_ol_version();

CREATE OR REPLACE FUNCTION audit_holdings_record_changes()
RETURNS TRIGGER AS $holdings_record_audit$
DECLARE
  jsonb JSONB;
  uuidtext TEXT;
  uuid UUID;
BEGIN
  jsonb = CASE WHEN TG_OP = 'DELETE' THEN OLD.jsonb ELSE NEW.jsonb END;
  uuidtext = md5(jsonb::text);
  uuidtext = overlay(uuidtext placing '4' from 13);
  uuidtext = overlay(uuidtext placing '8' from 17);
  uuid = uuidtext::uuid;
  WHILE EXISTS (SELECT 1 FROM audit_holdings_record WHERE id = uuid) LOOP
    uuid = next_uuid(uuid);
  END LOOP;
  jsonb = jsonb_build_object(
    'id', to_jsonb(uuid::text),
    'record', jsonb,
    'operation', to_jsonb(left(TG_OP, 1)),
    'createdDate', to_jsonb(current_timestamp::text));
  INSERT INTO audit_holdings_record VALUES (uuid, jsonb);
  RETURN CASE WHEN TG_OP = 'DELETE' THEN OLD ELSE NEW END;
END;
$holdings_record_audit$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS audit_holdings_record ON holdings_record CASCADE;
CREATE TRIGGER audit_holdings_record AFTER DELETE ON holdings_record
  FOR EACH ROW EXECUTE PROCEDURE audit_holdings_record_changes();

